import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "🌧️", high: 24, low: 18 },
    { day: "Thu", icon: "☁️", high: 25, low: 19 },
    { day: "Fri", icon: "☀️", high: 29, low: 21 }
  ]
}: Props) {
  return (
    <Card 
      shadow="md" 
      radius="xl" 
      padding={0}
      border={true}
    >
      <div style={{
        padding: 'var(--ggui-spacing-6, 24px)',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
        transition: 'transform 200ms ease-in-out, box-shadow 200ms ease-in-out',
        cursor: 'default'
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-2px)';
        e.currentTarget.style.boxShadow = 'var(--ggui-shape-shadow-lg)';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = 'none';
      }}
      >
        <Stack gap={24}>
          {/* Header Section */}
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city ?? 'Unknown City'}
            </Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition ?? 'Unknown Condition'}
            </Text>
          </Stack>

          {/* Hero Section */}
          <Stack direction="horizontal" align="center" justify="between">
            <div aria-label={`Current temperature: ${temperature} degrees ${unit}`}>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {temperature ?? 0}°{unit ?? 'C'}
              </Text>
            </div>
            <Text size="4xl" aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)' }}>
              {condition === "Sunny" ? "☀️" : condition === "Cloudy" ? "☁️" : condition === "Rainy" ? "🌧️" : "⛅"}
            </Text>
          </Stack>

          {/* Stats accent box */}
          <Box 
            background="var(--ggui-color-primary-50, #f0f9ff)" 
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            padding={16}
          >
            <Stack direction="horizontal" justify="around" align="center">
              <Stack align="center" gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
                  HUMIDITY
                </Text>
                <Text weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                  {humidity ?? 0}%
                </Text>
              </Stack>
              <Stack align="center" gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
                  WIND
                </Text>
                <Text weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                  {windSpeed ?? 0} km/h
                </Text>
              </Stack>
            </Stack>
          </Box>

          <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Forecast strip */}
          <Stack 
            direction="horizontal" 
            justify="between" 
            wrap={true} 
            gap={16}
            aria-label="5-day forecast"
          >
            {(forecast ?? []).map((item, index) => (
              <Stack key={`${item.day}-${index}`} align="center" gap={4} style={{ minWidth: '60px' }}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? '-'}
                </Text>
                <Text size="xl" aria-hidden="true">
                  {item.icon ?? '❓'}
                </Text>
                <Stack direction="horizontal" gap={4} justify="center">
                  <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {item.high ?? 0}°
                  </Text>
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)" size="sm">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </div>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box,
  Spacer,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{
    day?: string;
    icon?: string;
    high?: number;
    low?: number;
  }>;
}

export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = []
}: Props) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <>
      <MotionKeyframes />
      <div
        role="region"
        aria-label={`Weather in ${city ?? 'your city'}`}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        style={{
          width: '100%',
          maxWidth: '400px',
          animation: 'ggui-fadeIn 200ms ease-out',
          transition: 'transform 200ms ease-in-out',
          transform: isHovered ? 'scale(1.01)' : 'scale(1)',
          cursor: 'default'
        }}
      >
        <Card
          shadow={isHovered ? 'lg' : 'md'}
          padding={24}
          radius="xl"
          border={true}
          style={{
            backgroundColor: 'var(--ggui-color-surface, #ffffff)',
          }}
        >
          <Stack gap={24}>
            {/* Header Section */}
            <Stack gap={4}>
              <Heading level={3} color="var(--ggui-color-onSurface, #111827)">
                {city ?? 'Unknown City'}
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                {condition ?? 'Clear'}
              </Text>
            </Stack>

            {/* Hero Section */}
            <Stack direction="horizontal" align="start" gap={4}>
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-onSurface, #111827)"
                style={{ lineHeight: 'var(--ggui-font-lineHeight-none, 1)' }}
              >
                {temperature ?? '--'}
              </Text>
              <Text
                size="xl"
                weight="semibold"
                color="var(--ggui-color-primary-600, #0284c7)"
                style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
              >
                °{unit ?? 'C'}
              </Text>
            </Stack>

            {/* Details Section */}
            <Stack direction="horizontal" gap={16} justify="start">
              <Stack gap={0}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                  Humidity
                </Text>
                <Text variant="label" weight="semibold">
                  {humidity ?? 0}%
                </Text>
              </Stack>
              <Divider orientation="vertical" margin={4} />
              <Stack gap={0}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                  Wind
                </Text>
                <Text variant="label" weight="semibold">
                  {windSpeed ?? 0} km/h
                </Text>
              </Stack>
            </Stack>

            <Divider margin={4} color="var(--ggui-color-outlineVariant, #e5e7eb)" />

            {/* Forecast Section */}
            <Stack direction="horizontal" justify="between" align="center">
              {(forecast ?? []).map((item, index) => (
                <Stack key={index} gap={8} align="center" style={{ flex: 1 }}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                    {item?.day ?? '---'}
                  </Text>
                  <Text size="xl" style={{ margin: 'var(--ggui-spacing-1, 4px) 0' }}>
                    {item?.icon ?? '☀️'}
                  </Text>
                  <Stack gap={2} align="center">
                    <Text variant="label" weight="semibold" size="sm">
                      {item?.high ?? '--'}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)" size="xs">
                      {item?.low ?? '--'}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Card>
      </div>
    </>
  );
}

import React from 'react';
import { Card, Stack, Divider, Box, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  return (
    <div role="region" aria-label={`Weather information for ${city}`}>
      <Card shadow="md" padding={24} radius="lg" border={true}>
        <Stack gap={24}>
          <Stack gap={4} align="center">
            <Heading level={2}>{city}</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">
              {condition}
            </Text>
          </Stack>

          <Stack align="center" gap={4}>
            <Heading level={1} color="var(--ggui-color-primary-600)">
              {temperature}°{unit}
            </Heading>
          </Stack>

          <Stack direction="horizontal" justify="between">
            <Stack align="center">
              <Text variant="label">Humidity</Text>
              <Text variant="bodySmall">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={8} />
            <Stack align="center">
              <Text variant="label">Wind Speed</Text>
              <Text variant="bodySmall">{windSpeed} km/h</Text>
            </Stack>
          </Stack>

          <Divider />

          <Stack direction="horizontal" justify="between" gap={16} wrap={true}>
            {forecast.map((item, index) => (
              <Box key={index} padding={8} borderRadius={8} background="var(--ggui-color-surfaceVariant)">
                <Stack align="center" gap={4}>
                  <Text variant="label">{item.day ?? '—'}</Text>
                  <Text size="2xl">{item.icon ?? '?'}</Text>
                  <Text variant="bodySmall">
                    {item.high}° / {item.low}°
                  </Text>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </Card>
    </div>
  );
}
